import { describe, it, expect } from 'vitest'
import { ROLES, ROLE_LABELS, isAdmin } from '@/lib/constants/roles'

describe('ROLES', () => {
  it('defines all expected roles', () => {
    expect(ROLES.USER).toBe('user')
    expect(ROLES.COMERCIO).toBe('comercio')
    expect(ROLES.ADMIN).toBe('admin')
    expect(ROLES.SUPER_ADMIN).toBe('super_admin')
  })

  it('is frozen with as const (values not extensible)', () => {
    const roleValues = Object.values(ROLES)
    expect(roleValues).toContain('user')
    expect(roleValues).toContain('comercio')
    expect(roleValues).toContain('admin')
    expect(roleValues).toContain('super_admin')
    expect(roleValues).toHaveLength(4)
  })
})

describe('ROLE_LABELS', () => {
  it('provides human-readable labels for each role', () => {
    expect(ROLE_LABELS.user).toBe('Usuario')
    expect(ROLE_LABELS.comercio).toBe('Comercio')
    expect(ROLE_LABELS.admin).toBe('Administrador')
    expect(ROLE_LABELS.super_admin).toBe('Super Administrador')
  })

  it('covers all roles defined in ROLES', () => {
    const labels = Object.keys(ROLE_LABELS)
    const roles = Object.values(ROLES)
    expect(labels.sort()).toEqual(roles.sort())
  })
})

describe('isAdmin', () => {
  it('returns true for ADMIN role', () => {
    expect(isAdmin(ROLES.ADMIN)).toBe(true)
  })

  it('returns true for SUPER_ADMIN role', () => {
    expect(isAdmin(ROLES.SUPER_ADMIN)).toBe(true)
  })

  it('returns false for USER role', () => {
    expect(isAdmin(ROLES.USER)).toBe(false)
  })

  it('returns false for COMERCIO role', () => {
    expect(isAdmin(ROLES.COMERCIO)).toBe(false)
  })

  it('returns false for empty string', () => {
    expect(isAdmin('')).toBe(false)
  })

  it('returns false for unknown role', () => {
    expect(isAdmin('moderator')).toBe(false)
  })

  it('returns false for null-ish string', () => {
    expect(isAdmin('null')).toBe(false)
  })
})

import { describe, it, expect } from 'vitest'
import { APP_CONFIG } from '@/lib/constants/config'

describe('APP_CONFIG', () => {
  it('has the correct app name', () => {
    expect(APP_CONFIG.name).toBe('Paporla')
  })

  it('has the correct description', () => {
    expect(APP_CONFIG.description).toBe('Rescate alimentario')
  })

  it('has a support phone number', () => {
    expect(APP_CONFIG.supportPhone).toBe('+56 2 555 1234')
  })

  it('has a support email', () => {
    expect(APP_CONFIG.supportEmail).toBe('soporte@paporla.com')
  })

  it('has a numeric pickup code length', () => {
    expect(APP_CONFIG.pickupCodeLength).toBe(6)
    expect(typeof APP_CONFIG.pickupCodeLength).toBe('number')
  })

  it('has a positive reservation cancellation window', () => {
    expect(APP_CONFIG.reservationCancelationHours).toBe(2)
    expect(typeof APP_CONFIG.reservationCancelationHours).toBe('number')
    expect(APP_CONFIG.reservationCancelationHours).toBeGreaterThan(0)
  })

  it('exposes all expected configuration keys', () => {
    const keys = Object.keys(APP_CONFIG)
    expect(keys).toContain('name')
    expect(keys).toContain('description')
    expect(keys).toContain('supportPhone')
    expect(keys).toContain('supportEmail')
    expect(keys).toContain('pickupCodeLength')
    expect(keys).toContain('reservationCancelationHours')
    expect(keys).toHaveLength(6)
  })

  it('config values are stable (no mutations)', () => {
    const clone = { ...APP_CONFIG }
    expect(clone).toEqual(APP_CONFIG)
  })
})

import { describe, it, expect } from 'vitest'
import { pageVariants, fadeInUp, staggerContainer, scaleOnHover } from '@/lib/utils/motion'

describe('pageVariants', () => {
  it('has initial state with opacity 0 and y offset', () => {
    expect(pageVariants.initial).toEqual({ opacity: 0, y: 10 })
  })

  it('has animate state with full opacity and transition duration', () => {
    const animate = pageVariants.animate as Record<string, unknown>
    expect(animate.opacity).toBe(1)
    expect(animate.y).toBe(0)
    expect(animate.transition).toEqual({ duration: 0.3 })
  })

  it('has exit state with opacity 0 and negative y offset', () => {
    const exit = pageVariants.exit as Record<string, unknown>
    expect(exit.opacity).toBe(0)
    expect(exit.y).toBe(-10)
    expect(exit.transition).toEqual({ duration: 0.2 })
  })
})

describe('fadeInUp', () => {
  it('has initial state with opacity 0 and y 20', () => {
    expect(fadeInUp.initial).toEqual({ opacity: 0, y: 20 })
  })

  it('has animate state with opacity 1, y 0 and duration 0.4', () => {
    const animate = fadeInUp.animate as Record<string, unknown>
    expect(animate.opacity).toBe(1)
    expect(animate.y).toBe(0)
    expect(animate.transition).toEqual({ duration: 0.4 })
  })
})

describe('staggerContainer', () => {
  it('has empty initial state', () => {
    expect(staggerContainer.initial).toEqual({})
  })

  it('has animate state with staggerChildren and delayChildren', () => {
    const animate = staggerContainer.animate as Record<string, unknown>
    expect(animate.transition).toEqual({
      staggerChildren: 0.05,
      delayChildren: 0.1,
    })
  })
})

describe('scaleOnHover', () => {
  it('scales up on hover', () => {
    expect(scaleOnHover.whileHover).toEqual({ scale: 1.02 })
  })

  it('scales down on tap', () => {
    expect(scaleOnHover.whileTap).toEqual({ scale: 0.98 })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { NextRequest } from 'next/server'

// Mock getSupabaseAdmin before importing the module under test
vi.mock('@/lib/supabase/admin', () => ({
  getSupabaseAdmin: vi.fn(),
}))

// Import after mocks are set up
const { getSupabaseAdmin } = await import('@/lib/supabase/admin')

// Helper to create a minimal NextRequest-like object
function createMockRequest(headers: Record<string, string>, pathname = '/api/email'): NextRequest {
  const url = new URL(`http://localhost${pathname}`)
  return {
    headers: new Map(Object.entries(headers)) as unknown as Headers,
    nextUrl: url,
  } as unknown as NextRequest
}

describe('getClientIp', () => {
  let getClientIp: (request: NextRequest) => string

  beforeAll(async () => {
    // Dynamic import to avoid hoisting issues with vi.mock
    const mod = await import('@/lib/middleware/rateLimit')
    getClientIp = mod.getClientIp
  })

  it('returns real-ip when x-real-ip header is present', () => {
    const req = createMockRequest({ 'x-real-ip': '192.168.1.1' })
    expect(getClientIp(req)).toBe('192.168.1.1')
  })

  it('returns the first IP from x-forwarded-for when x-real-ip is absent', () => {
    const req = createMockRequest({ 'x-forwarded-for': '203.0.113.5, 198.51.100.2, 10.0.0.1' })
    expect(getClientIp(req)).toBe('203.0.113.5')
  })

  it('prefers x-real-ip over x-forwarded-for', () => {
    const req = createMockRequest({
      'x-real-ip': '10.0.0.42',
      'x-forwarded-for': '203.0.113.5, 198.51.100.2',
    })
    expect(getClientIp(req)).toBe('10.0.0.42')
  })

  it('trims whitespace from forwarded IPs', () => {
    const req = createMockRequest({ 'x-forwarded-for': '  203.0.113.5 , 198.51.100.2' })
    expect(getClientIp(req)).toBe('203.0.113.5')
  })

  it('returns "unknown" when no IP headers are present', () => {
    const req = createMockRequest({})
    expect(getClientIp(req)).toBe('unknown')
  })
})

describe('applyRateLimit', () => {
  let applyRateLimit: (request: NextRequest) => Promise<NextResponse | null>

  beforeAll(async () => {
    const mod = await import('@/lib/middleware/rateLimit')
    applyRateLimit = mod.applyRateLimit
  })

  beforeEach(() => {
    vi.clearAllMocks()
  })

  it('returns null for routes not in the rate-limit map', async () => {
    const req = createMockRequest({ 'x-real-ip': '1.2.3.4' }, '/api/unknown')
    const result = await applyRateLimit(req)
    expect(result).toBeNull()
  })

  it('returns null for non-api routes', async () => {
    const req = createMockRequest({}, '/')
    const result = await applyRateLimit(req)
    expect(result).toBeNull()
  })

  it('returns null for static assets', async () => {
    const req = createMockRequest({}, '/_next/static/chunk.js')
    const result = await applyRateLimit(req)
    expect(result).toBeNull()
  })

  it('matches prefix routes (e.g. /api/email/send matches /api/email)', async () => {
    const req = createMockRequest({ 'x-real-ip': '1.2.3.4' }, '/api/email/send')
    const result = await applyRateLimit(req)
    // Should not be null because /api/email is a configured route prefix
    expect(result).not.toBeNull()
  })
})

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { render, screen, act } from '@testing-library/react'
import { ThemeProvider, useTheme } from '@/context/ThemeContext'

// Stub component to test useTheme hook
function TestConsumer() {
  const { theme, toggleTheme, setTheme } = useTheme()
  return (
    <div>
      <span data-testid="theme-value">{theme}</span>
      <button data-testid="toggle-btn" onClick={toggleTheme}>
        Toggle
      </button>
      <button data-testid="set-light-btn" onClick={() => setTheme('light')}>
        Set Light
      </button>
      <button data-testid="set-dark-btn" onClick={() => setTheme('dark')}>
        Set Dark
      </button>
    </div>
  )
}

// Component that calls useTheme outside ThemeProvider to test error
function OrphanConsumer() {
  try {
    useTheme()
    return <div data-testid="no-error">OK</div>
  } catch (e: unknown) {
    return <div data-testid="error">{(e as Error).message}</div>
  }
}

describe('ThemeProvider', () => {
  const localStorageMock = (() => {
    let store: Record<string, string> = {}
    return {
      getItem: vi.fn((key: string) => store[key] ?? null),
      setItem: vi.fn((key: string, value: string) => {
        store[key] = value
      }),
      removeItem: vi.fn((key: string) => {
        delete store[key]
      }),
      clear: vi.fn(() => {
        store = {}
      }),
    }
  })()

  const matchMediaMock = vi.fn().mockImplementation((query: string) => ({
    matches: query.includes('light') ? false : true,
    media: query,
    onchange: null,
    addListener: vi.fn(),
    removeListener: vi.fn(),
    addEventListener: vi.fn(),
    removeEventListener: vi.fn(),
    dispatchEvent: vi.fn(),
  }))

  beforeEach(() => {
    Object.defineProperty(window, 'localStorage', { value: localStorageMock, writable: true })
    Object.defineProperty(window, 'matchMedia', { value: matchMediaMock, writable: true })
    localStorageMock.clear()
    vi.clearAllMocks()
    // Reset document class list
    document.documentElement.classList.remove('dark')
  })

  afterEach(() => {
    document.documentElement.classList.remove('dark')
  })

  it('renders children correctly', () => {
    render(
      <ThemeProvider>
        <div data-testid="child">Hello</div>
      </ThemeProvider>,
    )
    expect(screen.getByTestId('child')).toHaveTextContent('Hello')
  })

  it('defaults to dark theme when no localStorage value and prefers-color-scheme is dark', () => {
    render(
      <ThemeProvider>
        <TestConsumer />
      </ThemeProvider>,
    )
    // matchMedia returns matches=true for 'dark' queries
    expect(screen.getByTestId('theme-value')).toHaveTextContent('dark')
  })

  it('uses stored light theme from localStorage', () => {
    localStorageMock.getItem.mockReturnValueOnce('light')

    render(
      <ThemeProvider>
        <TestConsumer />
      </ThemeProvider>,
    )
    expect(screen.getByTestId('theme-value')).toHaveTextContent('light')
  })

  it('uses stored dark theme from localStorage', () => {
    localStorageMock.getItem.mockReturnValueOnce('dark')

    render(
      <ThemeProvider>
        <TestConsumer />
      </ThemeProvider>,
    )
    expect(screen.getByTestId('theme-value')).toHaveTextContent('dark')
  })

  it('toggles theme from dark to light', () => {
    render(
      <ThemeProvider>
        <TestConsumer />
      </ThemeProvider>,
    )

    expect(screen.getByTestId('theme-value')).toHaveTextContent('dark')

    act(() => {
      screen.getByTestId('toggle-btn').click()
    })

    expect(screen.getByTestId('theme-value')).toHaveTextContent('light')
    expect(localStorageMock.setItem).toHaveBeenCalledWith('paporla-theme', 'light')
  })

  it('toggles theme from light to dark', () => {
    localStorageMock.getItem.mockReturnValueOnce('light')

    render(
      <ThemeProvider>
        <TestConsumer />
      </ThemeProvider>,
    )

    expect(screen.getByTestId('theme-value')).toHaveTextContent('light')

    act(() => {
      screen.getByTestId('toggle-btn').click()
    })

    expect(screen.getByTestId('theme-value')).toHaveTextContent('dark')
    expect(localStorageMock.setItem).toHaveBeenCalledWith('paporla-theme', 'dark')
  })

  it('setTheme function updates theme to light', () => {
    render(
      <ThemeProvider>
        <TestConsumer />
      </ThemeProvider>,
    )

    act(() => {
      screen.getByTestId('set-light-btn').click()
    })

    expect(screen.getByTestId('theme-value')).toHaveTextContent('light')
    expect(localStorageMock.setItem).toHaveBeenCalledWith('paporla-theme', 'light')
  })

  it('setTheme function updates theme to dark', () => {
    localStorageMock.getItem.mockReturnValueOnce('light')

    render(
      <ThemeProvider>
        <TestConsumer />
      </ThemeProvider>,
    )

    act(() => {
      screen.getByTestId('set-dark-btn').click()
    })

    expect(screen.getByTestId('theme-value')).toHaveTextContent('dark')
    expect(localStorageMock.setItem).toHaveBeenCalledWith('paporla-theme', 'dark')
  })

  it('adds dark class to document element when theme is dark', () => {
    render(
      <ThemeProvider>
        <TestConsumer />
      </ThemeProvider>,
    )

    expect(document.documentElement.classList.contains('dark')).toBe(true)
  })

  it('removes dark class from document element when theme is light', () => {
    localStorageMock.getItem.mockReturnValueOnce('light')

    render(
      <ThemeProvider>
        <TestConsumer />
      </ThemeProvider>,
    )

